        str(cfg["observability"]["mlflow"]["tracking_uri"]), f"observability.mlflow"
    )
    phoenix = cfg["observability"].get("phoenix", {})
    if isinstance(phoenix, dict) and "host" in phoenix:
        require_loopback(str(phoenix["host"]), f"observability.phoenix")
    checkpointing = cfg.get("checkpointing", {})
    if isinstance(checkpointing, dict) and "host" in checkpointing:
        require_loopback(str(checkpointing["host"]), f"checkpointing")
    return cfg

